import React, { useState, useRef, useEffect, useMemo } from 'react';
import Fuse from 'fuse.js';
import { motion, AnimatePresence } from 'framer-motion';
import {
  MessageSquare,
  Search,
  History,
  Mic,
  Square,
  Play,
  Sparkles,
  Trash2,
  Calendar,
  ChevronRight,
  Wind,
  BarChart3,
  X,
  LayoutDashboard,
  LogOut,
  ArrowLeft,
  User
} from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import './index.css';

const API_BASE_URL = 'http://localhost:5000';

function App() {
  // Autenticação e Perfis
  const [usuario, setUsuario] = useState(() => {
    const saved = localStorage.getItem('usuario');
    return saved ? JSON.parse(saved) : null;
  });

  const [authMode, setAuthMode] = useState('login'); // 'login' or 'cadastro'
  const [authTipo, setAuthTipo] = useState('paciente'); // 'paciente' or 'psicologo'
  const [authNome, setAuthNome] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authSenha, setAuthSenha] = useState('');
  const [authPsicologoId, setAuthPsicologoId] = useState('');
  const [listaPsicologos, setListaPsicologos] = useState([]);

  // Estados do Chat e Histórico (Paciente)
  const [gravando, setGravando] = useState(false);
  const [transcricao, setTranscricao] = useState('');
  const [exercicio, setExercicio] = useState('');
  const [carregando, setCarregando] = useState(false);
  const [historico, setHistorico] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sessaoAtiva, setSessaoAtiva] = useState(null);
  const [currentView, setCurrentView] = useState('app'); // 'app', 'dashboard', 'agenda', 'financeiro', 'prontuario'
  const [showSOS, setShowSOS] = useState(false);
  const [breathingStep, setBreathingStep] = useState('Inspire');
  const [falando, setFalando] = useState(false);

  // Estados do Psicólogo
  const [listaPacientes, setListaPacientes] = useState([]);
  const [pacienteSelecionado, setPacienteSelecionado] = useState(null);

  // Cadastro de Paciente pelo Psicólogo
  const [showNovoPacienteForm, setShowNovoPacienteForm] = useState(false);
  const [novoPacNome, setNovoPacNome] = useState('');
  const [novoPacEmail, setNovoPacEmail] = useState('');
  const [novoPacSenha, setNovoPacSenha] = useState('');

  // Estados para Agenda (Fase 3)
  const [listaConsultas, setListaConsultas] = useState([]);
  const [dataSelecionada, setDataSelecionada] = useState('');
  const [horariosDisponiveis, setHorariosDisponiveis] = useState([]);
  const [horarioSelecionado, setHorarioSelecionado] = useState('');
  const [obsConsulta, setObsConsulta] = useState('');
  const [pacienteConsultaId, setPacienteConsultaId] = useState(''); // Usado na visão geral do Psicólogo para agendar

  // Estados para Financeiro (Fase 4)
  const [financeiroData, setFinanceiroData] = useState({ lancamentos: [], resumo: { total_receitas: 0, total_despesas: 0, lucro_liquido: 0 } });
  const [listaPacotes, setListaPacotes] = useState([]);

  // Formulário Financeiro
  const [finTipo, setFinTipo] = useState('receita'); // 'receita' or 'despesa'
  const [finCategoria, setFinCategoria] = useState('sessao');
  const [finValor, setFinValor] = useState('');
  const [finDescricao, setFinDescricao] = useState('');
  const [finStatus, setFinStatus] = useState('pago');
  const [finPacienteId, setFinPacienteId] = useState('');

  // Venda de Pacote
  const [pacSessoes, setPacSessoes] = useState('4');
  const [pacValorTotal, setPacValorTotal] = useState('');

  // Prontuário IA Consolidado (Novo)
  const [prontuarioConteudo, setProntuarioConteudo] = useState('');
  const [prontuarioData, setProntuarioData] = useState('');
  const [gerandoProntuario, setGerandoProntuario] = useState(false);

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const audioContextRef = useRef(null);

  // Carregar psicólogos para a tela de cadastro de pacientes
  useEffect(() => {
    if (authMode === 'cadastro' && authTipo === 'paciente') {
      fetch(`${API_BASE_URL}/psicologos`)
        .then(res => res.json())
        .then(data => {
          setListaPsicologos(data);
          if (data.length > 0) setAuthPsicologoId(data[0].id);
        })
        .catch(err => console.error("Erro ao buscar psicólogos:", err));
    }
  }, [authMode, authTipo]);

  // Carregar dados gerais ao iniciar
  useEffect(() => {
    if (usuario) {
      fetchConsultas();
      fetchFinanceiro();
      if (usuario.tipo === 'paciente') {
        fetchHistorico();
        fetchPacotes();
      } else if (usuario.tipo === 'psicologo') {
        fetchPacientes();
      }
    }
  }, [usuario]);

  // Carregar histórico, pacotes e prontuário IA do paciente selecionado
  useEffect(() => {
    if (usuario && usuario.tipo === 'psicologo' && pacienteSelecionado) {
      fetchHistorico(pacienteSelecionado.id);
      fetchPacotes(pacienteSelecionado.id);
      fetchConsultas();
      fetchProntuarioIA(pacienteSelecionado.id);
    } else {
      setHistorico([]);
      setListaPacotes([]);
      setProntuarioConteudo('');
      setProntuarioData('');
    }
    setSessaoAtiva(null);
    setTranscricao('');
    setExercicio('');
    setCurrentView('app'); // Reseta a aba interna ao trocar paciente
    setShowNovoPacienteForm(false); // Fecha cadastro se abrir paciente
  }, [pacienteSelecionado]);

  // Carregar horários livres quando a data mudar
  useEffect(() => {
    if (dataSelecionada) {
      fetchHorariosDisponiveis(dataSelecionada);
    } else {
      setHorariosDisponiveis([]);
    }
  }, [dataSelecionada]);

  // Fetch Handlers

  const fetchHistorico = async (pacienteId = null) => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/historico`;
      if (usuario.tipo === 'psicologo' && pacienteId) {
        url += `?paciente_id=${pacienteId}`;
      }

      const resp = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setHistorico(data.map(item => ({
        ...item,
        sentimento: item.sentimento || 'Neutro'
      })));
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    }
  };

  const fetchPacientes = async () => {
    if (!usuario || usuario.tipo !== 'psicologo') return;
    try {
      const resp = await fetch(`${API_BASE_URL}/pacientes`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setListaPacientes(data);
    } catch (err) {
      console.error("Erro ao carregar pacientes:", err);
    }
  };

  const fetchConsultas = async () => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/consultas`;
      if (usuario.tipo === 'psicologo' && pacienteSelecionado) {
        url += `?paciente_id=${pacienteSelecionado.id}`;
      }

      const resp = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setListaConsultas(data);
    } catch (err) {
      console.error("Erro ao carregar consultas:", err);
    }
  };

  const fetchHorariosDisponiveis = async (dataStr) => {
    if (!usuario || !dataStr) return;
    const psicologoId = usuario.tipo === 'paciente' ? usuario.psicologo_id : usuario.id;

    try {
      const resp = await fetch(`${API_BASE_URL}/horarios-disponiveis?psicologo_id=${psicologoId}&data=${dataStr}`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setHorariosDisponiveis(data);
      setHorarioSelecionado('');
    } catch (err) {
      console.error("Erro ao buscar horários livres:", err);
    }
  };

  const fetchFinanceiro = async () => {
    if (!usuario) return;
    try {
      const resp = await fetch(`${API_BASE_URL}/financeiro`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      if (usuario.tipo === 'psicologo') {
        setFinanceiroData(data);
      } else {
        setFinanceiroData({ lancamentos: data, resumo: { total_receitas: 0, total_despesas: 0, lucro_liquido: 0 } });
      }
    } catch (err) {
      console.error("Erro ao carregar financeiro:", err);
    }
  };

  const fetchPacotes = async (pacienteId = null) => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/pacotes`;
      if (usuario.tipo === 'psicologo' && pacienteId) {
        url += `?paciente_id=${pacienteId}`;
      } else if (usuario.tipo === 'psicologo' && !pacienteId) {
        return;
      }

      const resp = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setListaPacotes(data);
    } catch (err) {
      console.error("Erro ao carregar pacotes:", err);
    }
  };

  const fetchProntuárioIA = async (pacienteId) => {
    if (!usuario || usuario.tipo !== 'psicologo' || !pacienteId) return;
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteId}/prontuario-ia`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      if (resp.status === 401) {
        handleLogout();
        return;
      }
      const data = await resp.json();
      setProntuarioConteudo(data.conteudo || '');
      setProntuarioData(data.data_atualizacao || '');
    } catch (err) {
      console.error("Erro ao buscar prontuário IA:", err);
    }
  };

  // Mutação Handlers

  const handlePsicologoCadastrarPaciente = async (e) => {
    e.preventDefault();
    if (!novoPacNome || !novoPacEmail || !novoPacSenha) return;
    setCarregando(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/psicologo/cadastrar-paciente`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({
          nome: novoPacNome,
          email: novoPacEmail,
          senha: novoPacSenha
        })
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      if (resp.ok) {
        alert("Paciente cadastrado e vinculado com sucesso!");
        setNovoPacNome('');
        setNovoPacEmail('');
        setNovoPacSenha('');
        setShowNovoPacienteForm(false);
        fetchPacientes();
      } else {
        alert(data.erro || "Erro ao cadastrar paciente");
      }
    } catch (err) {
      console.error("Erro ao cadastrar:", err);
      alert("Erro de conexão.");
    } finally {
      setCarregando(false);
    }
  };

  const handleAgendarConsulta = async (e) => {
    e.preventDefault();
    if (!dataSelecionada || !horarioSelecionado) return;

    const isPsicologo = usuario.tipo === 'psicologo';
    const targetPacienteId = pacienteSelecionado ? pacienteSelecionado.id : (isPsicologo ? pacienteConsultaId : null);

    if (isPsicologo && !targetPacienteId) {
      alert("Por favor, selecione o paciente.");
      return;
    }

    setCarregando(true);
    try {
      const payload = {
        data_hora: `${dataSelecionada} ${horarioSelecionado}`,
        observacoes: obsConsulta
      };

      if (isPsicologo) {
        payload.paciente_id = targetPacienteId;
      }

      const resp = await fetch(`${API_BASE_URL}/consultas`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify(payload)
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      if (resp.ok) {
        alert("Consulta agendada com sucesso!");
        setDataSelecionada('');
        setHorariosDisponiveis([]);
        setHorarioSelecionado('');
        setObsConsulta('');
        setPacienteConsultaId('');
        fetchConsultas();
      } else {
        alert(data.erro || "Erro ao agendar consulta");
      }
    } catch (err) {
      console.error("Erro ao agendar:", err);
    } finally {
      setCarregando(false);
    }
  };

  const handleAlterarStatusConsulta = async (id, status) => {
    try {
      const resp = await fetch(`${API_BASE_URL}/consultas/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({ status })
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      if (resp.ok) {
        fetchConsultas();
        fetchFinanceiro(); 
        if (pacienteSelecionado) {
          fetchPacotes(pacienteSelecionado.id); 
        }
      } else {
        const data = await resp.json();
        alert(data.erro || "Erro ao atualizar consulta");
      }
    } catch (err) {
      console.error("Erro:", err);
    }
  };

  const handleCancelarConsulta = async (id) => {
    if (!window.confirm("Deseja realmente cancelar esta consulta?")) return;
    try {
      const resp = await fetch(`${API_BASE_URL}/consultas/${id}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      if (resp.ok) {
        fetchConsultas();
      }
    } catch (err) {
      console.error("Erro ao cancelar:", err);
    }
  };

  const handleLancarTransacao = async (e) => {
    e.preventDefault();
    if (!finValor || !finCategoria) return;
    setCarregando(true);
    try {
      const payload = {
        tipo: finTipo,
        categoria: finCategoria,
        valor: Number(finValor),
        descricao: finDescricao,
        status: finStatus
      };
      if (finTipo === 'receita' && finPacienteId) {
        payload.paciente_id = Number(finPacienteId);
      }

      const resp = await fetch(`${API_BASE_URL}/financeiro`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify(payload)
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      if (resp.ok) {
        alert("Lançamento financeiro realizado!");
        setFinValor('');
        setFinDescricao('');
        setFinPacienteId('');
        fetchFinanceiro();
      } else {
        const data = await resp.json();
        alert(data.erro || "Erro ao lançar transação");
      }
    } catch (err) {
      console.error("Erro ao lançar transação:", err);
    } finally {
      setCarregando(false);
    }
  };

  const handleAlterarStatusPagamento = async (id, status) => {
    try {
      const resp = await fetch(`${API_BASE_URL}/financeiro/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({ status })
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      if (resp.ok) {
        fetchFinanceiro();
      }
    } catch (err) {
      console.error("Erro ao alterar status financeiro:", err);
    }
  };

  const handleRemoverLancamento = async (id) => {
    if (!window.confirm("Deseja apagar esta transação financeiramente?")) return;
    try {
      const resp = await fetch(`${API_BASE_URL}/financeiro/${id}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      if (resp.ok) {
        fetchFinanceiro();
      }
    } catch (err) {
      console.error("Erro ao deletar lançamento:", err);
    }
  };

  const handleVenderPacote = async (e) => {
    e.preventDefault();
    if (!pacienteSelecionado || !pacSessoes || !pacValorTotal) return;
    setCarregando(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/pacotes`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({
          paciente_id: pacienteSelecionado.id,
          total_sessoes: Number(pacSessoes),
          valor_total: Number(pacValorTotal)
        })
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      if (resp.ok) {
        alert("Pacote registrado com sucesso!");
        setPacValorTotal('');
        fetchPacotes(pacienteSelecionado.id);
        fetchFinanceiro();
      } else {
        const data = await resp.json();
        alert(data.erro || "Erro ao vender pacote");
      }
    } catch (err) {
      console.error("Erro ao vender pacote:", err);
    } finally {
      setCarregando(false);
    }
  };

  const handleGerarProntuarioIA = async () => {
    if (!pacienteSelecionado) return;
    setGerandoProntuario(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteSelecionado.id}/prontuario-ia/gerar`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });
      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      if (resp.ok) {
        setProntuarioConteudo(data.conteudo);
        setProntuarioData(data.data_atualizacao);
        alert("Prontuário consolidado com IA atualizado!");
      } else {
        alert(data.erro || "Erro ao gerar prontuário");
      }
    } catch (err) {
      console.error("Erro ao gerar prontuário consolidado:", err);
      alert("Erro na conexão com a IA.");
    } finally {
      setGerandoProntuario(false);
    }
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!authEmail || !authSenha) return;
    setCarregando(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: authEmail, senha: authSenha })
      });
      const data = await resp.json();
      if (resp.ok) {
        setUsuario(data);
        localStorage.setItem('usuario', JSON.stringify(data));
        setAuthEmail('');
        setAuthSenha('');
      } else {
        alert(data.erro || "Erro ao realizar login");
      }
    } catch (err) {
      console.error("Erro no login:", err);
      alert("Erro na conexão com o servidor.");
    } finally {
      setCarregando(false);
    }
  };

  const handleCadastro = async (e) => {
    e.preventDefault();
    if (!authNome || !authEmail || !authSenha) return;
    setCarregando(true);
    try {
      const payload = {
        nome: authNome,
        email: authEmail,
        senha: authSenha,
        tipo: authTipo
      };
      if (authTipo === 'paciente' && authPsicologoId) {
        payload.psicologo_id = Number(authPsicologoId);
      }

      const resp = await fetch(`${API_BASE_URL}/cadastro`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await resp.json();
      if (resp.ok) {
        alert("Cadastro realizado com sucesso! Faça login para continuar.");
        setAuthMode('login');
        setAuthNome('');
      } else {
        alert(data.erro || "Erro ao realizar cadastro");
      }
    } catch (err) {
      console.error("Erro no cadastro:", err);
      alert("Erro na conexão com o servidor.");
    } finally {
      setCarregando(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('usuario');
    setUsuario(null);
    setHistorico([]);
    setListaPacientes([]);
    setListaConsultas([]);
    setFinanceiroData({ lancamentos: [], resumo: { total_receitas: 0, total_despesas: 0, lucro_liquido: 0 } });
    setListaPacotes([]);
    setPacienteSelecionado(null);
    setSessaoAtiva(null);
    setTranscricao('');
    setExercicio('');
    setCurrentView('app');
    window.speechSynthesis.cancel();
    setFalando(false);
  };

  // Animação de respiração e Som binaural 432Hz
  useEffect(() => {
    if (!showSOS) {
      if (audioContextRef.current) {
        audioContextRef.current.close().catch(() => { });
        audioContextRef.current = null;
      }
      return;
    }

    const AudioContext = window.AudioContext || window.webkitAudioContext;
    const ctx = new AudioContext();
    audioContextRef.current = ctx;

    const masterGain = ctx.createGain();
    masterGain.gain.setValueAtTime(0, ctx.currentTime);
    masterGain.gain.linearRampToValueAtTime(0.12, ctx.currentTime + 2);
    masterGain.connect(ctx.destination);

    const osc1 = ctx.createOscillator();
    osc1.type = 'sine';
    osc1.frequency.setValueAtTime(432, ctx.currentTime);

    const osc2 = ctx.createOscillator();
    osc2.type = 'sine';
    osc2.frequency.setValueAtTime(433.5, ctx.currentTime);

    osc1.connect(masterGain);
    osc2.connect(masterGain);

    osc1.start();
    osc2.start();

    const steps = ['Inspire', 'Segure', 'Expire', 'Segure'];
    let idx = 0;
    const interval = setInterval(() => {
      idx = (idx + 1) % steps.length;
      setBreathingStep(steps[idx]);
    }, 4000);

    return () => {
      clearInterval(interval);
      if (ctx.state !== 'closed') {
        masterGain.gain.linearRampToValueAtTime(0, ctx.currentTime + 1);
        setTimeout(() => ctx.close().catch(() => { }), 1100);
      }
    };
  }, [showSOS]);

  // TTS de Voz
  useEffect(() => {
    const carregarVozes = () => window.speechSynthesis.getVoices();
    carregarVozes();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = carregarVozes;
    }
  }, []);

  const falar = (texto) => {
    if (!texto || !('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    window.speechSynthesis.resume();

    const mensagemPura = texto
      .replace(/SENTIMENTO:.*?\n/g, '')
      .replace(/ABORDAGEM:/g, 'Abordagem teórica sugerida: ')
      .replace(/LAUDO:/g, 'Laudo de acompanhamento: ')
      .replace(/MAPA:/g, 'Mapa de sensibilidade: ')
      .replace(/ORIENTACAO:/g, 'Orientação técnica: ')
      .replace(/SESSAO:/g, 'Pauta para a próxima sessão: ')
      .replace(/[*#=_\-]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    const chunks = mensagemPura.match(/.{1,200}(?:\s|$)/g) || [mensagemPura];
    let currentChunk = 0;

    const speakNextChunk = () => {
      if (currentChunk >= chunks.length) {
        setFalando(false);
        return;
      }

      const locutor = new SpeechSynthesisUtterance(chunks[currentChunk]);
      const vozes = window.speechSynthesis.getVoices();

      const vozCalma = vozes.find(v => v.name.includes('Natural') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.name.includes('Neural') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.name.includes('Google') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.lang.includes('pt-BR'));

      if (vozCalma) locutor.voice = vozCalma;
      locutor.lang = 'pt-BR';
      locutor.rate = 1.0;
      locutor.pitch = 0.75;
      locutor.volume = 0.9;

      locutor.onstart = () => {
        setFalando(true);
      };

      locutor.onend = () => {
        currentChunk++;
        setTimeout(speakNextChunk, 500);
      };

      locutor.onerror = () => setFalando(false);
      window.speechSynthesis.speak(locutor);
    };

    speakNextChunk();
  };

  const pararDeFalar = () => {
    window.speechSynthesis.cancel();
    setFalando(false);
  };

