  // Subview: Prontuário Consolidado IA (Novo)
  const ProntuarioIAView = () => {
    const formatarProntuarioIA = (texto) => {
      if (!texto) return null;

      const linhas = texto.split('\n');
      return (
        <div className="clinical-report-markdown" style={{ lineHeight: '1.7', color: '#e2e8f0' }}>
          {linhas.map((linha, idx) => {
            const l = linha.trim();
            if (l.startsWith('###')) {
              return <h3 key={idx} style={{ color: 'var(--accent)', fontFamily: 'Outfit, sans-serif', fontSize: '1.25rem', marginTop: '1.5rem', marginBottom: '0.75rem', borderBottom: '1px solid rgba(255,255,255,0.05)', paddingBottom: '4px', display: 'flex', alignItems: 'center' }}>{l.replace('###', '').trim()}</h3>;
            }
            if (l.startsWith('##')) {
              return <h2 key={idx} style={{ color: 'white', fontFamily: 'Outfit, sans-serif', fontSize: '1.4rem', marginTop: '2rem', marginBottom: '1rem' }}>{l.replace('##', '').trim()}</h2>;
            }
            if (l.startsWith('-') || l.startsWith('*')) {
              return <li key={idx} style={{ marginLeft: '1.5rem', marginBottom: '0.4rem', listStyleType: 'disc' }}>{l.replace(/^[-*]\s*/, '')}</li>;
            }
            if (l === '') {
              return <div key={idx} style={{ height: '0.4rem' }} />;
            }

            const partes = l.split('**');
            if (partes.length > 1) {
              return (
                <p key={idx} style={{ marginBottom: '0.75rem' }}>
                  {partes.map((p, i) => i % 2 === 1 ? <strong key={i} style={{ color: 'white' }}>{p}</strong> : p)}
                </p>
              );
            }

            return <p key={idx} style={{ marginBottom: '0.75rem' }}>{l}</p>;
          })}
        </div>
      );
    };

    return (
      <div style={{ background: 'rgba(15, 23, 42, 0.4)', border: '1px solid var(--glass-border)', padding: '2rem', borderRadius: '1.5rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '1rem' }}>
          <div>
            <h3 style={{ margin: 0, fontFamily: 'Outfit, sans-serif', fontSize: '1.5rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <Sparkles size={20} style={{ color: 'var(--accent)' }} /> Prontuário Clínico Inteligente
            </h3>
            {prontuarioData && (
              <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Última atualização por IA: {prontuarioData}</span>
            )}
          </div>
          <button
            className="action-btn-success"
            onClick={handleGerarProntuarioIA}
            disabled={gerandoProntuario}
            style={{ display: 'flex', alignItems: 'center', gap: '8px', background: 'var(--accent)', color: 'white', borderColor: 'var(--accent)' }}
          >
            {gerandoProntuario ? 'Processando IA...' : prontuarioConteudo ? 'Atualizar Prontuário IA' : 'Gerar Prontuário IA'}
