        </div>

        {gerandoProntuario ? (
          <div style={{ textAlign: 'center', padding: '4rem' }}>
            <span className="loading-dots" style={{ fontSize: '1.2rem', color: 'var(--text-muted)' }}>Consolidando desabafos e analisando padrões evolutivos com o Gemini</span>
          </div>
        ) : prontuarioConteudo ? (
          formatarProntuarioIA(prontuarioConteudo)
        ) : (
          <div style={{ textAlign: 'center', padding: '4rem 2rem' }}>
            <Sparkles size={48} style={{ color: 'var(--accent)', opacity: 0.3, marginBottom: '1.5rem', display: 'block', margin: '0 auto' }} />
            <h4 style={{ fontSize: '1.2rem', marginBottom: '0.5rem' }}>Sem consolidação disponível</h4>
