            </p>
            <button className="auth-submit-btn" style={{ maxWidth: '250px', margin: '0 auto' }} onClick={handleGerarProntuarioIA}>
              Gerar Prontuário com IA 🪄
            </button>
          </div>
        )}
      </div>
    );
  };

  // VISTA 1: Tela de Autenticação (Não Logado)
  if (!usuario) {
