          </form>

          <div className="auth-switch-prompt">
            {authMode === 'login' ? (
              <>
                Não tem uma conta?
                <button className="auth-switch-link" onClick={() => setAuthMode('cadastro')}>
                  Cadastre-se
                </button>
              </>
            ) : (
              <>
                Já tem uma conta?
                <button className="auth-switch-link" onClick={() => setAuthMode('login')}>
                  Faça login
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    );
  }

  // VISTA 2: Visão do Psicólogo (Gerenciamento de Pacientes)
  if (usuario.tipo === 'psicologo') {
    return (
      <div className="app-wrapper">
        <aside className="sidebar">
          <div className="user-profile-header">
