          {/* Abas globais do Psicólogo (Apenas se nenhum paciente estiver selecionado) */}
          {!pacienteSelecionado && (
            <div style={{ padding: '1rem 1rem 0 1rem' }}>
              <button
                className={`nav-btn ${currentView === 'app' && !showNovoPacienteForm ? 'active' : ''}`}
