              >
                <User size={18} style={{ marginRight: 8 }} /> Pacientes
              </button>
              <button
                className={`nav-btn ${currentView === 'agenda' ? 'active' : ''}`}
                onClick={() => { setCurrentView('agenda'); fetchConsultas(); setShowNovoPacienteForm(false); }}
                style={{ marginBottom: '8px' }}
              >
                <Calendar size={18} style={{ marginRight: 8 }} /> Minha Agenda
              </button>
              <button
                className={`nav-btn ${currentView === 'financeiro' ? 'active' : ''}`}
                onClick={() => { setCurrentView('financeiro'); fetchFinanceiro(); setShowNovoPacienteForm(false); }}
                style={{ marginBottom: '8px' }}
              >
                <BarChart3 size={18} style={{ marginRight: 8 }} /> Painel Financeiro
              </button>
              <button
                className={`nav-btn ${showNovoPacienteForm ? 'active' : ''}`}
                onClick={() => { setShowNovoPacienteForm(true); setCurrentView('app'); }}
                style={{ marginBottom: '1rem', borderColor: 'var(--accent)', color: 'white', background: showNovoPacienteForm ? 'var(--accent)' : 'rgba(139, 92, 246, 0.1)' }}
              >
                + Cadastrar Paciente
              </button>
            </div>
          )}

          {currentView === 'app' && !pacienteSelecionado && !showNovoPacienteForm && (
            <>
              <div className="sidebar-header" style={{ padding: '0 1.5rem 1.5rem 1.5rem', borderBottom: '1px solid var(--glass-border)' }}>
                <h2 style={{ fontSize: '1.2rem', margin: 0 }}>
                  <History size={18} style={{ marginRight: 8 }} /> Pacientes Ativos
