                  <div className="form-group">
                    <label>Nome Completo do Paciente</label>
                    <input type="text" placeholder="Nome do paciente" value={novoPacNome} onChange={(e) => setNovoPacNome(e.target.value)} required />
                  </div>
                  <div className="form-group">
                    <label>E-mail</label>
                    <input type="email" placeholder="email@paciente.com" value={novoPacEmail} onChange={(e) => setNovoPacEmail(e.target.value)} required />
                  </div>
                  <div className="form-group">
                    <label>Senha Provisória</label>
                    <input type="password" placeholder="Defina a senha dele" value={novoPacSenha} onChange={(e) => setNovoPacSenha(e.target.value)} required />
