                  <button type="button" className="reset-btn" onClick={() => setShowNovoPacienteForm(false)}>Cancelar</button>
                </form>
              </div>
            ) : !pacienteSelecionado ? (
              // Visões Globais da Clínica
              currentView === 'agenda' ? (
                <div>
                  <h2 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '2.2rem', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <Calendar size={32} style={{ color: 'var(--accent)' }} /> Minha Agenda Geral
                  </h2>
                  <AgendaView />
